const Web3 = require('web3');
const privateKey = 'YOUR_PRIVATE_KEY';
const web3 = new Web3('YOUR_INFURA_ENDPOINT');

const account = web3.eth.accounts.privateKeyToAccount(privateKey);
web3.eth.accounts.wallet.add(account);

const sendTransaction = async (to, value) => {
  return await web3.eth.sendTransaction({
    from: account.address,
    to: to,
    value: value
  });
};

const interactWithContract = async (contractAddress, abi, functionName, parameters) => {
  const contract = new web3.eth.Contract(abi, contractAddress);

  const data = contract.methods[functionName](...parameters).encodeABI();
  const gas = await contract.methods[functionName](...parameters).estimateGas();

  const tx = {
    from: account.address,
    to: contractAddress,
    gas,
    data
  };

  return await web3.eth.sendTransaction(tx);
};